g_taskPermissions = {};
var TaskerTaskACLs = Class.create();
TaskerTaskACLs.prototype = {
    initialize: function(grTask) {
		//this.taskPermissions = {};
		// STRY0102083 - Tasker Numbering - if the system setting is glide.itil.assign.number.on.insert is to true, can't create new task
		// the key issue is new records.  for new records, the ACL needs to know 2 things:
		// - is it a sub task
		// - the state is new.  Set those 2 things and all ACLs should work.
		if (grTask.isNewRecord()){
			// NOTE any changes here should be validated below
			g_taskPermissions.state = "New";
			g_taskPermissions.isSubTask = grTask.parent + '' != '';
			var taskType = grTask.getDisplayValue("tasker_type");
			g_taskPermissions.isReviewType = (taskType == 'Concur with signature' 
						|| taskType == 'Approval without signature' 
						|| taskType == 'Approval with signature' 
						|| taskType == 'Concur without signature');
			g_taskPermissions.isStandardType = (taskType == 'Standard');
			return g_taskPermissions;
		}		
		var UserPermissions = new UserInfoScripts();			
		if(typeof g_taskPermissions != undefined){
			if (typeof g_taskPermissions.number != undefined){
				if(g_taskPermissions.number == grTask.getValue("number")){
					return g_taskPermissions;
				}
			}
		}

		var currentUser= gs.getUserID();
		var primary_assignee = '';
		var tasking_authority = '';
		var reviewer = '';
		var isTAExternal = false;
		var isExternalOutbound = false;
		var isExternal = false;
		var isSubTask = false;
		var parentTaskOwner = '';
		var parentTaskAssignedMember = '';
		var on_behalf_of = '';
		var isReviewRequired = false;
		var taskOwner = '';
		var assignedMember = '';
		var state = '';
		// STRY0105845 
		var originator = '';

		primary_assignee = grTask.getValue("primary_assignee") + '';
		tasking_authority = grTask.getValue("tasking_authority") + '';
		reviewer = grTask.getValue("u_reviewer") + '';
		isSubTask = grTask.parent + '' != '';
		on_behalf_of = grTask.on_behalf_of + '';
		// STRY0105845 
		originator = grTask.originator + '';
		isReviewRequired = (grTask.provide_response+''=='true');
		taskOwner = grTask.u_task_requester+'' != '' ? grTask.u_task_requester+'' : grTask.originator + '';
		assignedMember = grTask.assigned_to+'';
		state = (grTask.isNewRecord()) ? "New" : grTask.getValue("state") + '';

		if (tasking_authority != ''){
			// get Tasking Authority External flag
			var grTAOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
			if(grTAOU.get(tasking_authority))
				isTAExternal =  grTAOU.getValue('u_external_flag')+'';
		}
		isExternalOutbound = grTask.getValue('outbound') + '' == 'true';

		// get parent information
		if(isSubTask){
			var grParent = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grParent.get(grTask.getValue('parent'))){
				parentTaskOwner = grParent.u_task_requester + '';
				parentTaskAssignedMember = grParent.assigned_to + '';
			}
		}

		if (state == "11") {
			state = (primary_assignee == undefined || primary_assignee === "") ?
				"RejectedPrimaryAssignee" : "RejectedAssignment";
		}
		var stateNumeric = parseInt(state);
		state = isNaN(stateNumeric) ? state : stateNumeric;

		g_taskPermissions.number = grTask.getValue("number");
		g_taskPermissions.isTaskManagerOUTA = UserPermissions.IsUserOUTA(gs.getUserID(),primary_assignee);		
		g_taskPermissions.reviewerInOUTA_OU = UserPermissions.IsUserInOU(primary_assignee, reviewer);
		g_taskPermissions.isTAExternal = isTAExternal !='0';
		g_taskPermissions.isExternalOutbound = isExternalOutbound;
		g_taskPermissions.isExternal = isExternalOutbound || isTAExternal;
		g_taskPermissions.isSubTask = isSubTask;
		g_taskPermissions.isReviewRequired = isReviewRequired;
		g_taskPermissions.state = state;

		g_taskPermissions.isTaskerApplicationAdmin = gs.getUser().hasRole("x_153465_discovert.tasker_application_admin");
		g_taskPermissions.isTaskAdministratorGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
		// STRY0112587
		g_taskPermissions.isTaskExecutive = gs.getUser().hasRole("x_153465_discovert.Task_Executive");

		var OrgScripts = new ClientOrganizationalScripts();
		g_taskPermissions.isUserOUTAOfAnotherUserBasedOnDefaultOu = OrgScripts.isUserOUTAOfAnotherUserBasedOnDefaultOu(gs.getUserID(), taskOwner);
		g_taskPermissions.isTaskerUser = gs.getUser().hasRole("x_153465_discovert.tasker_user");
		g_taskPermissions.isParentTaskOwner = parentTaskOwner == currentUser;
		g_taskPermissions.isParentTaskAssignedMember = parentTaskAssignedMember == currentUser;
		g_taskPermissions.isUserInPrimaryAssigneeOU = UserPermissions.IsUserInOU(primary_assignee, gs.getUserID());
		g_taskPermissions.isOnBehalfOf = on_behalf_of == currentUser;
		g_taskPermissions.isReviewer = reviewer == currentUser;
		g_taskPermissions.isTaskOwner = taskOwner == currentUser;
		// STRY0105845 
		g_taskPermissions.isOriginator = originator == currentUser;

		g_taskPermissions.isAssignedMember = assignedMember == currentUser;
		g_taskPermissions.primaryOUMustMatchInternalTAOU = (gs.getProperty('x_153465_discovert.primary_office_must_match_Internal_tasking_authority') == 'true');

		taskType = grTask.getDisplayValue("tasker_type");
		g_taskPermissions.isReviewType = (taskType == 'Concur with signature' 
						|| taskType == 'Approval without signature' 
						|| taskType == 'Approval with signature' 
						|| taskType == 'Concur without signature');
		g_taskPermissions.isStandardType = (taskType == 'Standard');
    },

	canDelete: function (){
		var answer = false;
		if(g_taskPermissions.state == -6){
			answer = g_taskPermissions.isOriginator || g_taskPermissions.isTaskerApplicationAdmin;
		}
		return answer;
	},
	// STRY0107404
	setParentPermissions: function (){
		var answer = false;
		switch(g_taskPermissions.state){
			// New, Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}, Completed {3}, Completed Incomplete {4}, Cancelled {7}
			// STRY0105845 Draft {-6}
			case 'New': case -6: case -3: case -5: case 1: case 10: case 13: case 14: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 15: case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setClassificationPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			// New, Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}, Completed {3}, Cancelled {7}, Completed Incomplete {4}
			case 'New': case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15: case 3: case 7: case 4: 
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setTaskerTypePermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			// New,  
			case 'New': 
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1},
			case -3: case -5: case 1: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':
				answer = ((g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner));
				break;
			// Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}, Completed {3}, Completed Incomplete {4}, Cancelled {7}
			case 10: case 13: case 14: case 15: case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setTaskNamePermissions: function(){
		// originatorISEMPTY^on_behalf_ofISEMPTY^NQoriginatorDYNAMIC90d1921e5f510100a9ad2572f2b477fe^ORon_behalf_ofDYNAMIC90d1921e5f510100a9ad2572f2b477fe^EQ
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1},
			case -3: case -5: case 1: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':
				answer = ((g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner));
				break;
			//  Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}, Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 10: case 13: case 14: case 15: case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setObjectivePermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = !g_taskPermissions.isSubTask;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (!g_taskPermissions.isSubTask && (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner));
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setSubTaskObjectivePermissions: function(){
		var answer = false;
		// subtask objective is display only
		return answer;
	},

	setInstructionsPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setSignatureInstructionsPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setReviewSignedPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = false;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//In Review {14}
			case 14:
				// technically they should both be the same person
				answer = (g_taskPermissions.isReviewer || g_taskPermissions.isAssignedMember);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setPriorityPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setUrgencyPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setCategoryPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setSubCategoryPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 14: case 15:
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setWaitFlagPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, 
			case -3: case -5: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Assigned {1}, Accepted {10},
			case 1: case 10: 
				answer = (g_taskPermissions.isAssignedMember || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  In Review {14}
			case 14:
				answer = (g_taskPermissions.isStandardType && g_taskPermissions.isAssignedMember && !g_taskPermissions.isReviewRequired) || (g_taskPermissions.isReviewType || g_taskPermissions.isStandardType) && (g_taskPermissions.isReviewer || g_taskPermissions.isTaskOwner);
				break;
			//  Work in Progress {13}, Rework {15} Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 13: case 15: case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setOrderPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}
			case -3: case -5: case 'RejectedAssignment': case 'RejectedPrimaryAssignee':
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Assigned {1}, Accepted {10},
			case 1: case 10: 
				answer = (g_taskPermissions.isAssignedMember || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  In Review {14}
			case 14:
				answer = (g_taskPermissions.isStandardType && g_taskPermissions.isAssignedMember && !g_taskPermissions.isReviewRequired) || (g_taskPermissions.isReviewType || g_taskPermissions.isStandardType) && (g_taskPermissions.isReviewer || g_taskPermissions.isTaskOwner);
				break;
			//  Work in Progress {13}, Rework {15} Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 13: case 15: case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setSuspenseDatePermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 14: case 15: case 'RejectedAssignment':
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isTaskManagerOUTA || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			case 'RejectedPrimaryAssignee':
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setWarningDaysPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}
			case -3: case -5: case 1: case 10: case 13: case 14: case 15: case 'RejectedAssignment':
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isTaskManagerOUTA || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			case 'RejectedPrimaryAssignee':
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setExpectedStartDatePermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}, Assigned {1}, Accepted {10},
			case -3: case 1: case 10: 
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Unassigned {-5}
			case -5: case 'RejectedAssignment':
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isTaskManagerOUTA || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			case 'RejectedPrimaryAssignee':
				// STRY0112587
				answer = (g_taskPermissions.isTaskAdministratorGTA || g_taskPermissions.isTaskExecutive || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Work in Progress {13},  In Review {14}, Rework {15}, Completed {3}, Completed Incomplete {4},Cancelled {7}
			case 13: case 14: case 15: case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setEstimatedDurationPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New':
				answer = true;
