			case -5: case 1: 
				// who can edit comments_dt (reviewer Response) - if not standard type or Reviewer Type && isReviewer, isOnBehalfOf, isTaskOwner
				answer = (g_taskPermissions.isReviewType || g_taskPermissions.isStandardType) && (g_taskPermissions.isReviewer || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
