				answer = (g_taskPermissions.isAssignedMember || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			//  In Review {14}, Rework {15}
			case 14: case 15:
				if(g_taskPermissions.isReviewType){
					answer = (g_taskPermissions.isAssignedMember || g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				} else {
					answer = false;
				}
				break;
			// Completed {3}, Completed Incomplete {4},Cancelled {7} 
			case 3: case 4: case 7:
				answer = false;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},

	setCommentsPermissions: function(){
		var answer = false;
		switch(g_taskPermissions.state){
			case 'New': 
				answer = true;
				break;
			// STRY0105845 Draft {-6}
			case -6:
				answer = g_taskPermissions.isOriginator;
				break;
			// Waiting {-3}
			case -3: 
				answer = (g_taskPermissions.isOnBehalfOf || g_taskPermissions.isTaskOwner);
				break;
			// Unassigned {-5}, Assigned {1}, Accepted {10}, Work in Progress {13}, In Review {14}, Rework {15}, Completed {3}, Completed Incomplete {4},Cancelled {7} 
			case -5: case 1: case 10: case 13: case 14: case 15: case 'RejectedAssignment': case 'RejectedPrimaryAssignee': case 3: case 4: case 7:
				answer = g_taskPermissions.isTaskerUser;
				break;
			default:
				answer = false;
				break;
		}
		return answer;
	},	
	type: 'TaskerTaskACLs'
};
